mapper.select:
		/* com.erns.coching.rnd.mapper.LabElementInfDAO.getList */

    SELECT

    FROM T_LAB_ELEMENT_INF AA






        ORDER BY AA.LAB_ELE_SEQ DESC




			OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.rnd.mapper.LabElementInfDAO.load */

SELECT

FROM T_LAB_ELEMENT_INF AA

	AND AA.LAB_ELE_SEQ = #{labElementSeq	, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.rnd.mapper.LabElementInfDAO.insert */


	SELECT nextval('seq_t_lab_element_inf')


INSERT INTO T_LAB_ELEMENT_INF (
	LAB_ELE_SEQ
	, LAB_MST_SEQ
	, RAW_ELM_ID
	, RAW_ELM_KR
	, RAW_ELM_EN
) VALUES (
		#{labEleSeq	, jdbcType=INTEGER}
	, #{labMstSeq	, jdbcType=INTEGER}
	, #{rawElmId	, jdbcType=INTEGER}
	, #{rawElmKr	, jdbcType=VARCHAR}
	, #{rawElmEn	, jdbcType=VARCHAR}
)

mapper.update:
/* com.erns.coching.rnd.mapper.LabElementInfDAO.update */

UPDATE T_LAB_ELEMENT_INF SET
		LAB_MST_SEQ 	= #{labMstSeq	, jdbcType=INTEGER}
	, RAW_ELM_ID   	= #{rawElmId	, jdbcType=INTEGER}
	, RAW_ELM_KR   	= #{rawElmKr	, jdbcType=VARCHAR}
	, RAW_ELM_EN   	= #{rawElmEn	, jdbcType=VARCHAR}

	AND LAB_ELE_SEQ 	= #{labEleSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.rnd.mapper.LabElementInfDAO.delete */

DELETE FROM T_LAB_ELEMENT_INF

	AND LAB_ELE_SEQ = #{labElementSeq, jdbcType=INTEGER}

/* com.erns.coching.rnd.mapper.LabElementInfDAO.deleteByLabMstSeq */

DELETE FROM T_LAB_ELEMENT_INF

  AND LAB_MST_SEQ = #{labSeq, jdbcType=INTEGER}
